// =============================================================================
// Seed dataset for the bmv.vin content tables (Task #96, T009; translations
// added in Task #98).
// =============================================================================
//
// Pure data + a single `seedBmvVinContent()` runner. Idempotent — every
// row is upserted by its natural key (`bmvVinStorage.upsert*` already
// handles INSERT-or-UPDATE), so re-running the seed never duplicates and
// edits made through the admin panel are preserved unless the seed source
// is explicitly updated.
//
// Translations: each multi-locale field is authored for all 11 supported
// locales — see SEED_LOCALE_ORDER below. Brand names (BMW, MINI, ALPINA,
// Rolls-Royce, BMW Motorrad), VIN codes (WMI/VDS/VIS), SA codes, paint
// codes and plant city names stay untranslated by intent. German uses FIN
// for VIN per industry convention.
// =============================================================================

import { bmvVinStorage } from "../storage";
import { BMV_VIN_BRANDS, BMV_VIN_FACET_KINDS, BRAND_LABEL, BRAND_WMIS, type BmvVinBrand } from "../../shared/bmv-vin/feature-registry";
import type {
  InsertBmvVinHomeCopy,
  InsertBmvVinBrandDecoderCopy,
  InsertBmvVinGlossary,
  InsertBmvVinGuide,
  InsertBmvVinFacetBlurb,
} from "../../shared/schema";
import type { LocaleCode } from "../../shared/i18n/types";

// Order MUST match the tuple positions used in `tr()` calls below.
export const SEED_LOCALE_ORDER: readonly LocaleCode[] = [
  "en", "de-DE", "fr-FR", "es-ES", "es-MX", "it-IT", "pt-BR", "en-ZA", "ru-RU", "zh-CN", "ko-KR",
] as const;

type Tr11 = readonly [string, string, string, string, string, string, string, string, string, string, string];
type LocText = Record<string, string>;
type Faq = { q: LocText; a: LocText };

function tr(t: Tr11): LocText {
  const out: LocText = {};
  for (let i = 0; i < SEED_LOCALE_ORDER.length; i++) out[SEED_LOCALE_ORDER[i]] = t[i];
  return out;
}

// Convenience: produce a multi-locale string by formatting per-locale
// templates with positional args. Each template has access to the same
// formatting positions, e.g. label, wmiList.
function trf<A extends Record<string, string>>(args: A, t: Tr11): LocText {
  const out: LocText = {};
  for (let i = 0; i < SEED_LOCALE_ORDER.length; i++) {
    let s = t[i];
    for (const [k, v] of Object.entries(args)) s = s.split(`{${k}}`).join(v);
    out[SEED_LOCALE_ORDER[i]] = s;
  }
  return out;
}

