// Helper to build an Article guide entry from positional translation tuples.
function buildSimpleArticle(
  slug: string,
  category: string,
  titleT: string[],
  summaryT: string[],
  bodyT: string[],
  relatedSlugs?: string[],
): GuideSeed[] {
  return [{
    slug, schemaType: "Article" as const, category,
    title: tr(titleT as unknown as Tr11),
    summary: tr(summaryT as unknown as Tr11),
    body: tr(bodyT as unknown as Tr11),
    relatedSlugs,
  }];
}

