// -----------------------------------------------------------------------------
// Runner
// -----------------------------------------------------------------------------
export interface SeedReport {
  homeCopy: number;
  brandDecoderCopy: number;
  glossary: number;
  guides: number;
  facetBlurbs: number;
}

export async function seedBmvVinContent(): Promise<SeedReport> {
  // The seed literals use multi-locale `Record<string,string>` shapes for
  // jsonb columns; the Insert types declare those columns as `unknown`
  // (drizzle-zod default for jsonb). We cast through the Insert type rather
  // than `any` so the top-level field names (key, brand, slug, term, ...)
  // are still checked.
  await bmvVinStorage.upsertHomeCopy(HOME_COPY as InsertBmvVinHomeCopy);
  let brandDecoderCopy = 0;
  for (const brand of BMV_VIN_BRANDS) {
    await bmvVinStorage.upsertBrandDecoderCopy(brandCopy(brand) as InsertBmvVinBrandDecoderCopy);
    brandDecoderCopy++;
  }
  let glossary = 0;
  for (const g of GLOSSARY) {
    await bmvVinStorage.upsertGlossary(g as InsertBmvVinGlossary);
    glossary++;
  }
  let guides = 0;
  for (const guide of GUIDES) {
    await bmvVinStorage.upsertGuide(guide as InsertBmvVinGuide);
    guides++;
  }
  let facetBlurbs = 0;
  for (const fb of FACET_BLURBS) {
    await bmvVinStorage.upsertFacetBlurb(fb as InsertBmvVinFacetBlurb);
    facetBlurbs++;
  }
  // Touch the unused facet kind list so TypeScript doesn't drop the import
  // and we get a free guard against the kind enum drifting.
  void BMV_VIN_FACET_KINDS;
  return { homeCopy: 1, brandDecoderCopy, glossary, guides, facetBlurbs };
}

// -----------------------------------------------------------------------------
// Coverage helpers (re-exported for the audit script).
// -----------------------------------------------------------------------------
export const SEED_DATA_FOR_COVERAGE = {
  homeCopy: HOME_COPY,
  brandDecoderCopy: BMV_VIN_BRANDS.map(brandCopy),
  glossary: GLOSSARY,
  guides: GUIDES,
  facetBlurbs: FACET_BLURBS,
} as const;
